import java.io.File;
import java.io.FileWriter;
import java.io.IOException;

public class SetupGame {
    public static void main(String[] args) {
        System.out.println("開始自動分裝並生成 AI Shooter Challenge 專案檔案...");

        String srcPath = "src" + File.separator;
        String[] packages = {"main", "player", "enemy", "bullet", "map", "util"};

        for (String pkg : packages) {
            File dir = new File(srcPath + pkg);
            if (!dir.exists()) {
                dir.mkdirs();
            }
        }

        writeFile(srcPath + "util" + File.separator + "Node.java", getSubNodeCode());
        writeFile(srcPath + "map" + File.separator + "Map.java", getMapCode());
        writeFile(srcPath + "bullet" + File.separator + "Bullet.java", getBulletCode());
        writeFile(srcPath + "player" + File.separator + "Player.java", getPlayerCode());
        writeFile(srcPath + "enemy" + File.separator + "Enemy.java", getEnemyCode());
        writeFile(srcPath + "main" + File.separator + "GamePanel.java", getGamePanelCode());
        writeFile(srcPath + "main" + File.separator + "GameFrame.java", getGameFrameCode());

        System.out.println("\n🎉 所有 Java 檔案已成功自動分裝生成！");
        System.out.println("請至 src/main/ 目錄下編譯並執行 GameFrame.java 即可開始挑戰！");
    }

    private static void writeFile(String filePath, String content) {
        try (FileWriter writer = new FileWriter(filePath)) {
            writer.write(content);
            System.out.println("[已建置] " + filePath);
        } catch (IOException e) {
            System.err.println("寫入檔案失敗: " + filePath + " -> " + e.getMessage());
        }
    }

    private static String getSubNodeCode() {
        return "package util;\n\npublic class Node {\n    public int x, y;\n    public Node parent;\n    public Node(int x, int y) {\n        this.x = x;\n        this.y = y;\n        this.parent = null;\n    }\n    public Node(int x, int y, Node parent) {\n        this.x = x;\n        this.y = y;\n        this.parent = parent;\n    }\n}\n";
    }

    private static String getMapCode() {
        return "package map;\n\nimport java.awt.Color;\nimport java.awt.Graphics;\n\npublic class Map {\n    public static final int COLS = 20;\n    public static final int ROWS = 15;\n    public static final int TILE_SIZE = 40;\n    private int[][] grid;\n    public Map() {\n        grid = new int[COLS][ROWS];\n        generateObstacles();\n    }\n    private void generateObstacles() {\n        grid[5][5] = 1; grid[5][6] = 1; grid[5][7] = 1;\n        grid[14][3] = 1; grid[14][4] = 1;\n        grid[10][10] = 1; grid[11][10] = 1; grid[12][10] = 1;\n        grid[3][11] = 1; grid[4][11] = 1;\n    }\n    public boolean isObstacle(int x, int y) {\n        if (x < 0 || x >= COLS || y < 0 || y >= ROWS) return true;\n        return grid[x][y] == 1;\n    }\n    public void draw(Graphics g) {\n        for (int i = 0; i < COLS; i++) {\n            for (int j = 0; j < ROWS; j++) {\n                if (grid[i][j] == 1) {\n                    g.setColor(Color.DARK_GRAY);\n                    g.fillRect(i * TILE_SIZE, j * TILE_SIZE, TILE_SIZE, TILE_SIZE);\n                    g.setColor(Color.BLACK);\n                    g.drawRect(i * TILE_SIZE, j * TILE_SIZE, TILE_SIZE, TILE_SIZE);\n                }\n            }\n        }\n    }\n}\n";
    }

    private static String getBulletCode() {
        return "package bullet;\n\nimport java.awt.Color;\nimport java.awt.Graphics;\nimport java.awt.Rectangle;\n\npublic class Bullet {\n    private int x, y;\n    private int speed = 10;\n    private int radius = 6;\n    private boolean active = true;\n    public Bullet(int x, int y) {\n        this.x = x;\n        this.y = y;\n    }\n    public void update() {\n        y -= speed;\n        if (y < 0) active = false;\n    }\n    public void draw(Graphics g) {\n        g.setColor(Color.YELLOW);\n        g.fillOval(x - radius, y - radius, radius * 2, radius * 2);\n    }\n    public boolean isActive() { return active; }\n    public void setInactive() { this.active = false; }\n    public Rectangle getBounds() {\n        return new Rectangle(x - radius, y - radius, radius * 2, radius * 2);\n    }\n}\n";
    }

    private static String getPlayerCode() {
        return "package player;\n\nimport java.awt.Color;\nimport java.awt.Graphics;\nimport java.awt.Rectangle;\nimport map.Map;\n\npublic class Player {\n    private int x, y;\n    private int speed = 5;\n    private int width = 30;\n    private int height = 30;\n    private int hp = 3;\n    public Player(int x, int y) {\n        this.x = x;\n        this.y = y;\n    }\n    public void move(int dx, int dy) {\n        int nextX = x + dx * speed;\n        int nextY = y + dy * speed;\n        int gridX = nextX / Map.TILE_SIZE;\n        int gridY = nextY / Map.TILE_SIZE;\n        if (gridX >= 0 && gridX < Map.COLS && gridY >= 0 && gridY < Map.ROWS) {\n            x = Math.max(0, Math.min(nextX, Map.COLS * Map.TILE_SIZE - width));\n            y = Math.max(0, Math.min(nextY, Map.ROWS * Map.TILE_SIZE - height));\n        }\n    }\n    public void draw(Graphics g) {\n        g.setColor(Color.BLUE);\n        int[] xPoints = {x + width / 2, x, x + width};\n        int[] yPoints = {y, y + height, y + height};\n        g.fillPolygon(xPoints, yPoints, 3);\n    }\n    public int getX() { return x; }\n    public int getY() { return y; }\n    public int getGridX() { return (x + width / 2) / Map.TILE_SIZE; }\n    public int getGridY() { return (y + height / 2) / Map.TILE_SIZE; }\n    public int getHp() { return hp; }\n    public void decreaseHp() { hp--; }\n    public Rectangle getBounds() { return new Rectangle(x, y, width, height); }\n}\n";
    }

    private static String getEnemyCode() {
        return "package enemy;\n\nimport java.awt.Color;\nimport java.awt.Graphics;\nimport java.awt.Rectangle;\nimport java.util.*;\nimport map.Map;\nimport util.Node;\n\npublic class Enemy {\n    private int x, y;\n    private int gridX, gridY;\n    private int size = 28;\n    private int moveDelay = 20;\n    private int delayCounter = 0;\n    public Enemy(int gridX, int gridY) {\n        this.gridX = gridX;\n        this.gridY = gridY;\n        this.x = gridX * Map.TILE_SIZE + (Map.TILE_SIZE - size) / 2;\n        this.y = gridY * Map.TILE_SIZE + (Map.TILE_SIZE - size) / 2;\n    }\n    public List<Node> findPathBFS(Map map, int targetGridX, int targetGridY) {\n        boolean[][] visited = new boolean[Map.COLS][Map.ROWS];\n        Queue<Node> queue = new LinkedList<>();\n        queue.add(new Node(this.gridX, this.gridY));\n        visited[this.gridX][this.gridY] = true;\n        Node targetNode = null;\n        int[] dx = {0, 0, -1, 1};\n        int[] dy = {-1, 1, 0, 0};\n        while (!queue.isEmpty()) {\n            Node curr = queue.poll();\n            if (curr.x == targetGridX && curr.y == targetGridY) {\n                targetNode = curr;\n                break;\n            }\n            for (int i = 0; i < 4; i++) {\n                int nextX = curr.x + dx[i];\n                int nextY = curr.y + dy[i];\n                if (nextX >= 0 && nextX < Map.COLS && nextY >= 0 && nextY < Map.ROWS) {\n                    if (!visited[nextX][nextY] && !map.isObstacle(nextX, nextY)) {\n                        visited[nextX][nextY] = true;\n                        queue.add(new Node(nextX, nextY, curr));\n                    }\n                }\n            }\n        }\n        List<Node> path = new ArrayList<>();\n        if (targetNode != null) {\n            Node temp = targetNode;\n            while (temp != null) {\n                path.add(0, temp);\n                temp = temp.parent;\n            }\n        }\n        return path;\n    }\n    public void update(Map map, int playerGridX, int playerGridY) {\n        delayCounter++;\n        if (delayCounter >= moveDelay) {\n            delayCounter = 0;\n            List<Node> path = findPathBFS(map, playerGridX, playerGridY);\n            if (path.size() > 1) {\n                Node nextStep = path.get(1);\n                this.gridX = nextStep.x;\n                this.gridY = nextStep.y;\n            }\n        }\n        int targetX = gridX * Map.TILE_SIZE + (Map.TILE_SIZE - size) / 2;\n        int targetY = gridY * Map.TILE_SIZE + (Map.TILE_SIZE - size) / 2;\n        if (x < targetX) x += 2;\n        if (x > targetX) x -= 2;\n        if (y < targetY) y += 2;\n        if (y > targetY) y -= 2;\n    }\n    public void draw(Graphics g) {\n        g.setColor(Color.RED);\n        int[] xPoints = {x + size / 2, x, x + size};\n        int[] yPoints = {y + size, y, y};\n        g.fillPolygon(xPoints, yPoints, 3);\n    }\n    public Rectangle getBounds() { return new Rectangle(x, y, size, size); }\n}\n";
    }

    private static String getGamePanelCode() {
        return "package main;\n\nimport bullet.Bullet;\nimport enemy.Enemy;\nimport java.awt.*;\nimport java.awt.event.*;\nimport java.util.ArrayList;\nimport java.util.Iterator;\nimport java.util.List;\nimport java.util.Random;\nimport javax.swing.JPanel;\nimport javax.swing.Timer;\nimport map.Map;\nimport player.Player;\n\npublic class GamePanel extends JPanel implements ActionListener, KeyListener {\n    private Timer timer;\n    private Player player;\n    private Map gameMap;\n    private List<Bullet> bullets;\n    private List<Enemy> enemies;\n    private int score = 0, level = 1, enemySpawnTimer = 0;\n    private boolean isPaused = false, isGameOver = false;\n    private boolean keyUp, keyDown, keyLeft, keyRight;\n    public GamePanel() {\n        setFocusable(true);\n        setPreferredSize(new Dimension(Map.COLS * Map.TILE_SIZE, Map.ROWS * Map.TILE_SIZE));\n        setBackground(Color.BLACK);\n        addKeyListener(this);\n        initGame();\n        timer = new Timer(16, this);\n        timer.start();\n    }\n    private void initGame() {\n        player = new Player(400, 500);\n        gameMap = new Map();\n        bullets = new ArrayList<>();\n        enemies = new ArrayList<>();\n        score = 0; level = 1; isGameOver = false; isPaused = false;\n        spawnEnemy();\n    }\n    private void spawnEnemy() {\n        Random rand = new Random();\n        int rx, ry;\n        do {\n            rx = rand.nextInt(Map.COLS);\n            ry = rand.nextInt(4);\n        } while (gameMap.isObstacle(rx, ry));\n        enemies.add(new Enemy(rx, ry));\n    }\n    @Override\n    public void actionPerformed(ActionEvent e) {\n        if (!isPaused && !isGameOver) updateGame();\n        repaint();\n    }\n    private void updateGame() {\n        int dx = 0, dy = 0;\n        if (keyUp) dy = -1;\n        if (keyDown) dy = 1;\n        if (keyLeft) dx = -1;\n        if (keyRight) dx = 1;\n        player.move(dx, dy);\n        Iterator<Bullet> bulletIt = bullets.iterator();\n        while (bulletIt.hasNext()) {\n            Bullet b = bulletIt.next();\n            b.update();\n            if (!b.isActive()) bulletIt.remove();\n        }\n        enemySpawnTimer++;\n        if (enemySpawnTimer > 120) { spawnEnemy(); enemySpawnTimer = 0; }\n        for (Enemy enemy : enemies) enemy.update(gameMap, player.getGridX(), player.getGridY());\n        checkCollisions();\n    }\n    private void checkCollisions() {\n        for (Bullet b : bullets) {\n            for (Enemy enemy : enemies) {\n                if (b.getBounds().intersects(enemy.getBounds())) {\n                    b.setInactive();\n                    enemies.remove(enemy);\n                    score += 100;\n                    if (score % 500 == 0) level++;\n                    break;\n                }\n            }\n        }\n        Iterator<Enemy> enemyIt = enemies.iterator();\n        while (enemyIt.hasNext()) {\n            Enemy enemy = enemyIt.next();\n            if (enemy.getBounds().intersects(player.getBounds())) {\n                player.decreaseHp();\n                enemyIt.remove();\n                if (player.getHp() <= 0) isGameOver = true;\n            }\n        }\n    }\n    @Override\n    protected void paintComponent(Graphics g) {\n        super.paintComponent(g);\n        gameMap.draw(g);\n        player.draw(g);\n        for (Bullet b : bullets) b.draw(g);\n        for (Enemy e : enemies) e.draw(g);\n        g.setColor(Color.WHITE);\n        g.setFont(new Font(\"Arial\", Font.BOLD, 16));\n        g.drawString(\"SCORE: \" + score, 20, 25);\n        g.drawString(\"HP: \" + player.getHp(), 200, 25);\n        g.drawString(\"LEVEL: \" + level, 350, 25);\n        if (isPaused) {\n            g.setColor(new Color(0, 0, 0, 150));\n            g.fillRect(0, 0, getWidth(), getHeight());\n            g.setColor(Color.YELLOW);\n            g.setFont(new Font(\"Arial\", Font.BOLD, 36));\n            g.drawString(\"PAUSED\", getWidth() / 2 - 70, getHeight() / 2);\n        }\n        if (isGameOver) {\n            g.setColor(new Color(0, 0, 0, 200));\n            g.fillRect(0, 0, getWidth(), getHeight());\n            g.setColor(Color.RED);\n            g.setFont(new Font(\"Arial\", Font.BOLD, 36));\n            g.drawString(\"GAME OVER\", getWidth() / 2 - 110, getHeight() / 2 - 20);\n        }\n    }\n    @Override\n    public void keyPressed(KeyEvent e) {\n        int key = e.getKeyCode();\n        if (key == KeyEvent.VK_W || key == KeyEvent.VK_UP) keyUp = true;\n        if (key == KeyEvent.VK_S || key == KeyEvent.VK_DOWN) keyDown = true;\n        if (key == KeyEvent.VK_A || key == KeyEvent.VK_LEFT) keyLeft = true;\n        if (key == KeyEvent.VK_D || key == KeyEvent.VK_RIGHT) keyRight = true;\n        if (key == KeyEvent.VK_SPACE && !isGameOver && !isPaused) {\n            bullets.add(new Bullet(player.getX() + 15, player.getY()));\n        }\n        if (key == KeyEvent.VK_P) isPaused = !isPaused;\n        if (key == KeyEvent.VK_R) initGame();\n    }\n    @Override\n    public void keyReleased(KeyEvent e) {\n        int key = e.getKeyCode();\n        if (key == KeyEvent.VK_W || key == KeyEvent.VK_UP) keyUp = false;\n        if (key == KeyEvent.VK_S || key == KeyEvent.VK_DOWN) keyDown = false;\n        if (key == KeyEvent.VK_A || key == KeyEvent.VK_LEFT) keyLeft = false;\n        if (key == KeyEvent.VK_D || key == KeyEvent.VK_RIGHT) keyRight = false;\n    }\n    @Override public void keyTyped(KeyEvent e) {}\n}\n";
    }

    private static String getGameFrameCode() {
        return "package main;\n\nimport javax.swing.JFrame;\n\npublic class GameFrame extends JFrame {\n    public GameFrame() {\n        setTitle(\"AI Shooter Challenge - BFS Pathfinding\");\n        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);\n        setResizable(false);\n        add(new GamePanel());\n        pack();\n        setLocationRelativeTo(null);\n        setVisible(true);\n    }\n    public static void main(String[] args) {\n        new GameFrame();\n    }\n}\n";
    }
}